MainWindow::MainWindow(QWidget* parent)
    : QMainWindow(parent) {
    setAcceptDrops(true);  // Enable drag-drop for files
    
    // Top Goal Bar
    QWidget* goalBar = createGoalBar();
    QWidget* goalBarContainer = new QWidget(this);
