    const QString jsonString = R"({
        "goal": "Implement user auth service",
        "task_graph": [
            {
                "task_id": "T1_FEAT",
                "agent": "feature",
                "prompt": "Implement the core login function using email and password.",
                "dependencies": []
            },
            {
